#include<bits/stdc++.h>
using namespace std;
typedef long long ll;
const int mod=1e9+7;
int a[110000],b[110000];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
            b[a[i]]=i;
        }
        int ans=1;
        int l,r;
        l=r=b[0];
        for(int i=1;i<n;i++)
        {
            int t=b[i];
            if(l<=t&&t<=r)
            {
                ans=(1LL*ans*((r-l+1-i)%mod))%mod;
            }
            else
            {
                l=min(l,t);
                r=max(r,t);
            }
        }
        printf("%d\n",ans);
    }
}
